// Generated by Claude Opus 4.6

import { BackupItem } from '@eclipse-che/common';
import userEvent from '@testing-library/user-event';
import React from 'react';

import { BackupSelectorField } from '@/pages/RestoreFromBackup/DefaultRegistryForm/BackupSelectorField';
import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

const mockOnChange = jest.fn();

const mockBackups: BackupItem[] = [
  {
    workspaceName: 'active-workspace',
    imageUrl: 'registry.example.com/ns/active-workspace:latest',
    timestamp: '2026-02-11T12:00:00Z',
    sizeBytes: 1024,
    workspaceExists: true,
    labels: {},
  },
  {
    workspaceName: 'deleted-workspace',
    imageUrl: 'registry.example.com/ns/deleted-workspace:latest',
    timestamp: '2026-02-10T12:00:00Z',
    sizeBytes: 2048,
    workspaceExists: false,
    labels: {},
  },
];

const { renderComponent } = getComponentRenderer(getComponent);

describe('BackupSelectorField', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should render null when backups is empty', () => {
    renderComponent({ backups: [] });

    expect(screen.queryByText('Select a backup')).not.toBeInTheDocument();
  });

  test('should render select with placeholder when backups provided', () => {
    renderComponent();

    expect(screen.getByText('Select a backup to restore')).toBeInTheDocument();
  });

  test('should show Active suffix for active workspaces', async () => {
    renderComponent();

    await userEvent.click(screen.getByText('Select a backup to restore'));

    expect(screen.getByText('active-workspace (Active)')).toBeInTheDocument();
  });

  test('should show Deleted suffix for deleted workspaces', async () => {
    renderComponent();

    await userEvent.click(screen.getByText('Select a backup to restore'));

    expect(screen.getByText('deleted-workspace (Deleted)')).toBeInTheDocument();
  });

  test('should call onChange with correct backup when option selected', async () => {
    renderComponent();

    await userEvent.click(screen.getByText('Select a backup to restore'));
    await userEvent.click(screen.getByText('deleted-workspace (Deleted)'));

    expect(mockOnChange).toHaveBeenCalledWith(mockBackups[1]);
  });
});

function getComponent(
  options: {
    backups?: BackupItem[];
    selectedBackup?: BackupItem;
  } = {},
) {
  return (
    <BackupSelectorField
      backups={options.backups ?? mockBackups}
      selectedBackup={options.selectedBackup}
      onChange={mockOnChange}
    />
  );
}
